  wd:Q113480442 wdt:P1694 ?competition.
  ?edition wdt:P1694 ?competition.
  ?edition wdt:P1241 wd:Q620722.
}

SELECT (COUNT(*) AS ?wins) WHERE {
  ?competition rdfs:label "US Open Cup"@en.
  ?edition wdt:P1694 ?competition.
  ?edition wdt:P1241 wd:Q620722.
}

SELECT (COUNT(*) AS ?wins) WHERE {
  ?edition wdt:P1694 ?competition.
  ?competition rdfs:label "US Open Cup"@en.
  ?edition wdt:P4146 wd:Q620722.
