SELECT (COUNT(*) AS ?wins) WHERE {
  ?edition rdfs:label ?label .
  FILTER (LANG(?label) = 'en') .
  FILTER (CONTAINS(STR(?label), 'US Open Cup')) .
  ?edition wdt:P1241 wd:Q620722 .
}

SELECT (COUNT(*) AS ?wins) WHERE {
  ?competition rdfs:label ?compLabel .
  FILTER (LANG(?compLabel) = 'en' && CONTAINS(STR(?compLabel), 'US Open Cup'))
  ?edition wdt:P155 ?competition .
  ?edition wdt:P1241 wd:Q620722 .
}

